record.field:
for source in records:
    source.with_delay(
        channel="root.newsassistant",
        description=f"Bulk scrape: {source.name}",
    )._scrape_listing()
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Scrape Jobs Queued",
        "message": f"{len(records)} source(s) queued for scraping.",
        "type": "info",
        "sticky": False,
    },
}

count = 0
for article in records.filtered(lambda a: a.state != 'skipped'):
    article.with_delay(
        channel="root.newsassistant",
        description=f"Bulk re-fetch: {article.title[:50]}",
    )._fetch_and_extract()
    count += 1
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Re-fetch Jobs Queued",
        "message": f"{count} article(s) queued for re-fetching.",
        "type": "info",
        "sticky": False,
    },
}

records.filtered(lambda a: a.state != 'skipped').write({"state": "skipped", "active": False})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Skipped",
        "message": f"{len(records)} article(s) marked as skipped and archived.",
        "type": "info",
        "sticky": False,
    },
}

records.write({
    "state": "pending",
    "status_message": False,
    "last_error_date": False,
    "retry_count": 0,
    "active": True,
})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Articles Reset",
        "message": f"{len(records)} article(s) reset to pending and unarchived.",
        "type": "info",
        "sticky": False,
    },
}

if record.state != 'skipped':
    record.with_delay(
        channel="root.newsassistant",
        description=f"Manual re-fetch: {record.title[:50]}",
    )._fetch_and_extract()
    action = {
        "type": "ir.actions.client",
        "tag": "display_notification",
        "params": {
            "title": "Re-fetch Started",
            "message": "Re-fetching article in background...",
            "type": "info",
            "sticky": False,
        },
    }
else:
    action = {
        "type": "ir.actions.client",
        "tag": "display_notification",
        "params": {
            "title": "Cannot Re-fetch",
            "message": "Cannot re-fetch skipped articles. Reset first.",
            "type": "warning",
            "sticky": False,
        },
    }

if record.state != 'skipped':
    record.write({"state": "skipped", "active": False})
    action = {
        "type": "ir.actions.client",
        "tag": "display_notification",
        "params": {
            "title": "Article Skipped",
            "message": "Article marked as skipped and archived.",
            "type": "info",
            "sticky": False,
        },
    }
else:
    action = {
        "type": "ir.actions.client",
        "tag": "display_notification",
        "params": {
            "title": "Already Skipped",
            "message": "This article is already skipped.",
            "type": "warning",
            "sticky": False,
        },
    }

record.write({
    "state": "pending",
    "status_message": False,
    "last_error_date": False,
    "retry_count": 0,
    "active": True,
})
action = {
    "type": "ir.actions.client",
    "tag": "display_notification",
    "params": {
        "title": "Article Reset",
        "message": "Article reset to pending and unarchived.",
        "type": "info",
        "sticky": False,
    },
}
